import React, { useState } from 'react';
import { ngoApi } from '../../../services/api';

export default function CreateFundsPage() {
  const [userCert, setUserCert] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);
  const [funds, setFunds] = useState([]);

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    setFunds([]);
    try {
      const res = await ngoApi.getAllFunds({ userCert });
      const data = res?.data ?? res;
      if (!data || (Array.isArray(data) && data.length === 0)) {
        setMessage('No funds found for this UserCert.');
      } else {
        setFunds(Array.isArray(data) ? data : [data]);
      }
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Failed to fetch funds');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 900, margin: '0 auto' }}>
      <form onSubmit={onSubmit} style={{ marginBottom: 20 }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={userCert}
            onChange={(e) => setUserCert(e.target.value)}
            placeholder="Enter userCert to fetch associated funds"
            style={{ width: '100%' }}
            required
          />
        </div>

        <button type="submit" disabled={loading} style={{ marginTop: 12 }}>
          {loading ? 'Fetching...' : 'Fetch Funds'}
        </button>
      </form>

      {message && <div style={{ marginBottom: 12 }}>{String(message)}</div>}

      {funds.length > 0 && (
        <div>
          <h3>Funds associated with UserCert</h3>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Fund ID</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>NGO ID</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Title</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Purpose</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Target</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Raised</th>
              </tr>
            </thead>
            <tbody>
              {funds.map((fund, idx) => (
                <tr key={fund.fundId ?? idx}>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.fundId}
                  </td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.ngoId}
                  </td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.title}
                  </td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.purpose}
                  </td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.fundTarget}
                  </td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>
                    {fund.raisedAmount ?? fund.raised}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
